 1	import React, { FC } from 'react';
 2	import classNames from 'classnames';
 3	
 4	import { useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
 5	import { Button, ButtonVariant, SplitItem, Tooltip } from '@patternfly/react-core';
 6	import { VMActionIconDetails } from '@virtualmachines/actions/components/VMActionsIconBar/utils/types';
 7	
 8	import '../VMActionsIconBar.scss';
 9	
10	const ActionIconButton: FC<VMActionIconDetails> = ({
11	  action,
12	  Icon,
13	  iconClassname,
14	  isDisabled,
15	  isHidden,
16	}) => {
17	  const [actionAllowed] = useAccessReview(action?.accessReview);
18	
19	  const handleClick = () => {
20	    if (typeof action?.cta === 'function') {
21	      action?.cta();
22	    }
23	  };
24	
25	  return (
26	    !isHidden && (
27	      <SplitItem>
28	        <Tooltip content={action?.label}>
29	          <Button
30	            className="vm-actions-icon-bar__button"
31	            data-test-id={`${action?.id}-button`}
32	            isDisabled={!actionAllowed || isDisabled}
33	            onClick={handleClick}
34	            variant={ButtonVariant.link}
35	          >
36	            <Icon className={classNames(iconClassname, 'vm-actions-icon-bar__icon')} />
37	          </Button>
38	        </Tooltip>
39	      </SplitItem>
40	    )
41	  );
42	};
43	
44	export default ActionIconButton;

